declare(strict_types=1);require_once dirname(__DIR__,2).'/includes/auth.php';require_once dirname(__DIR__,2).'/includes/alerts.php';require_once dirname(__DIR__,2).'/includes/audit.php';exigirRol(['usuario']);$id=filter_var($_POST['id']??0,FILTER_VALIDATE_INT,['options'=>['min_range'=>1]])?:0;$accion=(string)($_POST['accion']??'');if(($_SERVER['REQUEST_METHOD']??'')!=='POST'||!validarTokenCsrf(isset($_POST['csrf_token'])?(string)$_POST['csrf_token']:null)||!$id||!in_array($accion,['visto','resuelto'],true)){ateneaFlash('error','Solicitud invalida','No fue posible actualizar el aviso.');header('Location: '.atenea_url('src/estudiantes/avisos.php'));exit;}$pdo=obtenerConexion();$sql=$accion==='visto'?"UPDATE admin_notices SET status='visto',read_at=COALESCE(read_at,NOW()) WHERE id=:id AND user_id=:user AND status='pendiente'":"UPDATE admin_notices SET status='resuelto',read_at=COALESCE(read_at,NOW()),resolved_at=NOW() WHERE id=:id AND user_id=:user AND status IN ('pendiente','visto')";$q=$pdo->prepare($sql);$q->execute(['id'=>$id,'user'=>(int)$_SESSION['usuario_id']]);if($q->rowCount()){actualizarActividadUsuario((int)$_SESSION['usuario_id'],$pdo);registrarAuditoria(['actor_user_id'=>(int)$_SESSION['usuario_id'],'target_user_id'=>(int)$_SESSION['usuario_id'],'event_type'=>'notice.'.$accion,'module'=>'notices','entity_type'=>'admin_notice','entity_id'=>$id,'action'=>$accion,'result'=>'success','description'=>'El usuario actualizo el estado de un aviso administrativo.']);ateneaFlash('success','Aviso actualizado','El estado del aviso se guardo correctamente.');}else ateneaFlash('warning','Sin cambios','El aviso ya habia sido actualizado o no pertenece a tu cuenta.');header('Location: '.atenea_url('src/estudiantes/avisos.php'));exit;
